            // Combine normalized arrival and area deltas
            double arrival_delta = (worst_arrival - best_arrival) / (best_arrival + 1e-6);
            double area_delta = (area_local - best_area_flow) / (best_area_flow + 1e-6);
            double combined_delta = arrival_delta + area_delta;
            double probability = exp(-combined_delta / temperature);
            accept = (rand() / (double)RAND_MAX) < probability;
            iteration++;
