            if (abs((int)cuts.cuts(index)[i]->size() - (int)current_size) <= 1) {
                candidate_cuts.push_back(i);
            }
        }
        if (!candidate_cuts.empty()) {
            best_cut = candidate_cuts[rand() % candidate_cuts.size()];
        }
    }

